"""Pure helpers powering prior_fix_lookup.py — extracted so the CLI module
stays under the project's per-file LOC budget AND so the helpers are easy
to unit-test without subprocess.

No I/O, no globals. Functions:
  - extract_signature(error_text) -> str | None
  - render_markdown(matches, signature) -> str
"""

from __future__ import annotations

import re
from typing import Any

# Python traceback frame: `  File "<path>", line <N>, in <fn>`
_PY_FRAME_RE = re.compile(r'File\s+"([^"]+)",\s+line\s+(\d+)')

# JavaScript stack frame: `  at <fn> (<path>:<line>:<col>)` or `at <path>:<line>:<col>`
_JS_FRAME_RE = re.compile(r"at\s+(?:[^\s(]+\s+\()?([^()\s:]+):(\d+):(?:\d+)\)?")

# `<Type>: <msg>` (Python/JS error line)
_TYPE_MSG_RE = re.compile(r"^([A-Z][A-Za-z0-9_]*(?:Error|Exception|Warning)):\s+(.+?)\s*$")


def _normalize_path(path: str) -> str:
    """Strip noise (e.g. site-packages prefixes, leading <>) so signatures stay stable."""
    p = path.strip().strip("<>")
    # Drop common noise prefixes so signatures match across machines.
    markers = ("site-packages/", "node_modules/", "dist-packages/")
    for marker in markers:
        idx = p.find(marker)
        if idx >= 0:
            p = p[idx + len(marker) :]
    return p


def _extract_python_signature(text: str) -> str | None:
    """Build `<Type> <primary_file>:<line>` from a Python traceback."""
    frames = _PY_FRAME_RE.findall(text)
    if not frames:
        return None
    # Primary frame: the deepest (last) one — that's where the exception fired.
    file_, line = frames[-1]
    err_type: str | None = None
    for line_text in reversed(text.splitlines()):
        match = _TYPE_MSG_RE.match(line_text.strip())
        if match:
            err_type = match.group(1)
            break
    err_type = err_type or "Error"
    return f"{err_type} {_normalize_path(file_)}:{line}"


def _extract_js_signature(text: str) -> str | None:
    """Build `<Type> <primary_file>:<line>` from a JavaScript stack trace."""
    frames = _JS_FRAME_RE.findall(text)
    if not frames:
        return None
    file_, line = frames[0]
    err_type: str | None = None
    for line_text in text.splitlines():
        match = _TYPE_MSG_RE.match(line_text.strip())
        if match:
            err_type = match.group(1)
            break
    err_type = err_type or "Error"
    return f"{err_type} {_normalize_path(file_)}:{line}"


def _extract_generic_signature(text: str) -> str | None:
    """Build `<Type> <msg>` from a `<Type>: <msg>` line with no stack."""
    for line_text in text.splitlines():
        match = _TYPE_MSG_RE.match(line_text.strip())
        if match:
            err_type, msg = match.group(1), match.group(2)
            # Trim very long messages so the signature stays grep-able.
            if len(msg) > 80:
                msg = msg[:77] + "..."
            return f"{err_type} {msg}"
    return None


def extract_signature(error_text: str) -> str | None:
    """Best-effort: normalize an error blob to `<Type> <primary_path>:<lineno>`.

    Tries Python traceback → JS stack → generic `<Type>: <msg>`. Returns
    None when nothing parses (caller skips cleanly in that case).
    """
    if not isinstance(error_text, str) or not error_text.strip():
        return None
    text = error_text.strip()

    # Python traceback wins when both are present (Python errors can contain
    # snippets that look like JS frames).
    if "Traceback" in text or _PY_FRAME_RE.search(text):
        sig = _extract_python_signature(text)
        if sig is not None:
            return sig

    if _JS_FRAME_RE.search(text):
        sig = _extract_js_signature(text)
        if sig is not None:
            return sig

    return _extract_generic_signature(text)


# ---------------------------------------------------------------------------
# match rendering
# ---------------------------------------------------------------------------


def _entity_name(entity: dict[str, Any]) -> str:
    name = entity.get("name")
    return name if isinstance(name, str) else "<unnamed>"


def _entity_type(entity: dict[str, Any]) -> str:
    et = entity.get("entityType")
    return et if isinstance(et, str) else "<no-type>"


def _observations(entity: dict[str, Any]) -> list[str]:
    observations = entity.get("observations")
    if not isinstance(observations, list):
        return []
    return [o for o in observations if isinstance(o, str)]


def extract_matches(result: Any, limit: int = 3) -> list[dict[str, Any]]:
    """Pull the `entities` / `nodes` list out of a search_nodes result, capped."""
    if isinstance(result, list):
        entities = [e for e in result if isinstance(e, dict)]
    elif isinstance(result, dict):
        entities = []
        for key in ("entities", "nodes", "result"):
            value = result.get(key)
            if isinstance(value, list):
                entities = [e for e in value if isinstance(e, dict)]
                break
    else:
        entities = []
    return entities[:limit]


def render_markdown(matches: list[dict[str, Any]], signature: str) -> str:
    """Human-friendly Markdown report of the top matches."""
    lines: list[str] = []
    lines.append("# Prior-fix matches")
    lines.append("")
    lines.append(f"**Signature**: `{signature}`")
    lines.append("")

    if not matches:
        lines.append("No prior matches in the memory KG.")
        return "\n".join(lines) + "\n"

    lines.append("| # | Name | Type | Obs # | Top observation |")
    lines.append("|---|------|------|-------|-----------------|")
    for i, entity in enumerate(matches, 1):
        observations = _observations(entity)
        top = observations[0] if observations else "(no observations)"
        # Trim for table readability.
        if len(top) > 80:
            top = top[:77] + "..."
        # Escape pipe chars in cell content so the table doesn't break.
        top = top.replace("|", "\\|")
        lines.append(
            f"| {i} | `{_entity_name(entity)}` | {_entity_type(entity)} | "
            f"{len(observations)} | {top} |"
        )

    return "\n".join(lines) + "\n"
